from openpyxl import load_workbook
import pandas as pd

def extract_deals(path, label):
    wb = load_workbook(path, read_only=True)
    ws = wb.active
    all_rows = list(ws.iter_rows(values_only=True))

    # Buscar sección Deals
    deals_header_idx = None
    for i, row in enumerate(all_rows):
        if row[0] == 'Time' and row[3] == 'Type':
            deals_header_idx = i
            break

    # Si no, buscar por contenido diferente
    if deals_header_idx is None:
        for i, row in enumerate(all_rows):
            if any('Profit' in str(v) for v in row if v is not None) and row[0] not in [None, 'Strategy Tester Report']:
                if 'Time' in str(row[0]) or 'Deal' in str(row[0]):
                    deals_header_idx = i
                    break

    print(f"\n{label}: deals_header_idx={deals_header_idx}")

    # Escanear buscando la sección con P&L
    for i in range(len(all_rows)-1, max(0, len(all_rows)-100), -1):
        row = all_rows[i]
        if any(v is not None for v in row):
            print(f"  Ultima fila no-nula R{i+1}: {row}")
            break

    # Buscar todas las secciones con encabezados
    print(f"\n  Buscando secciones en {label}:")
    for i, row in enumerate(all_rows):
        if row[0] in ['Orders', 'Deals', 'Results', 'Settings', 'Statistics']:
            print(f"  R{i+1}: {row[0]}")
        if row[0] == 'Time' or (row[0] is not None and 'Time' in str(row[0])):
            print(f"  R{i+1} (posible header): {row[:8]}")

for f, lbl in [('FR_XAU_BK', 'FR (OOS)'), ('BK_XAU_BK', 'BK (IS)')]:
    extract_deals(f'/mnt/user-data/uploads/{f}.xlsx', lbl)
EOF

