const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType,
  VerticalAlign, PageNumber, LevelFormat, Header, Footer, Tab,
  TabStopType, TabStopPosition
} = require('docx');
const fs = require('fs');

// ─── Color palette ───────────────────────────────────────────
const C = {
  darkBlue:   '1F3864',
  medBlue:    '2E75B6',
  lightBlue:  'D6E4F0',
  green:      '375623',
  lightGreen: 'E2EFDA',
  red:        '9C2B2B',
  lightRed:   'FCE4D6',
  amber:      '7F6000',
  lightAmber: 'FFEB9C',
  gray:       '595959',
  lightGray:  'F2F2F2',
  white:      'FFFFFF',
  black:      '000000',
};

// ─── Helpers ──────────────────────────────────────────────────
const border = (color = 'CCCCCC') => ({ style: BorderStyle.SINGLE, size: 1, color });
const borders = (c) => { const b = border(c); return { top: b, bottom: b, left: b, right: b }; };
const cellMargins = { top: 80, bottom: 80, left: 120, right: 120 };
const sp = (before, after) => ({ before, after });

function hdr(text, level, color = C.darkBlue) {
  return new Paragraph({
    heading: level,
    spacing: sp(240, 120),
    children: [new TextRun({ text, bold: true, color, font: 'Arial' })]
  });
}

function para(runs, align, spacing) {
  const children = Array.isArray(runs) ? runs : [new TextRun({ text: runs, font: 'Arial', size: 22 })];
  return new Paragraph({ children, alignment: align || AlignmentType.LEFT, spacing: spacing || sp(60, 60) });
}

function bold(text, color, size) {
  return new TextRun({ text, bold: true, font: 'Arial', size: size || 22, color: color || C.black });
}
function normal(text, color, size) {
  return new TextRun({ text, font: 'Arial', size: size || 22, color: color || C.black });
}
function mono(text) {
  return new TextRun({ text, font: 'Courier New', size: 20, color: C.darkBlue });
}

function bullet(text, bold_prefix) {
  const children = bold_prefix
    ? [new TextRun({ text: bold_prefix, bold: true, font: 'Arial', size: 22 }),
       new TextRun({ text, font: 'Arial', size: 22 })]
    : [new TextRun({ text, font: 'Arial', size: 22 })];
  return new Paragraph({
    numbering: { reference: 'bullets', level: 0 },
    children,
    spacing: sp(40, 40),
  });
}

function rule(text, num) {
  return new Paragraph({
    numbering: { reference: 'numbers', level: 0 },
    children: [new TextRun({ text, font: 'Arial', size: 22 })],
    spacing: sp(40, 40),
  });
}

// ─── Table builders ──────────────────────────────────────────
function makeTable(headers, rows, colWidths, headerColor = C.medBlue) {
  const total = colWidths.reduce((a, b) => a + b, 0);
  function headerCell(text, w) {
    return new TableCell({
      borders: borders(headerColor),
      width: { size: w, type: WidthType.DXA },
      shading: { fill: headerColor, type: ShadingType.CLEAR },
      margins: cellMargins,
      verticalAlign: VerticalAlign.CENTER,
      children: [new Paragraph({
        alignment: AlignmentType.CENTER,
        children: [new TextRun({ text, bold: true, font: 'Arial', size: 20, color: C.white })]
      })]
    });
  }
  function dataCell(text, w, fill, align, textColor, isBold) {
    return new TableCell({
      borders: borders('CCCCCC'),
      width: { size: w, type: WidthType.DXA },
      shading: { fill: fill || C.white, type: ShadingType.CLEAR },
      margins: cellMargins,
      verticalAlign: VerticalAlign.CENTER,
      children: [new Paragraph({
        alignment: align || AlignmentType.CENTER,
        children: [new TextRun({ text: String(text), font: 'Arial', size: 20, color: textColor || C.black, bold: isBold || false })]
      })]
    });
  }

  const tableRows = [
    new TableRow({
      tableHeader: true,
      children: headers.map((h, i) => headerCell(h, colWidths[i]))
    }),
    ...rows.map((row, ri) => new TableRow({
      children: row.map((cell, ci) => {
        if (typeof cell === 'object' && cell !== null && 'v' in cell) {
          return dataCell(cell.v, colWidths[ci], cell.fill, cell.align, cell.color, cell.bold);
        }
        const fill = ri % 2 === 0 ? C.white : C.lightGray;
        return dataCell(cell, colWidths[ci], fill);
      })
    }))
  ];

  return new Table({
    width: { size: total, type: WidthType.DXA },
    columnWidths: colWidths,
    rows: tableRows,
  });
}

function spacer(n = 1) {
  return Array(n).fill(new Paragraph({ children: [new TextRun('')], spacing: sp(60, 60) }));
}

// ─── Section divider ─────────────────────────────────────────
function sectionLine(color = C.medBlue) {
  return new Paragraph({
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color, space: 1 } },
    spacing: sp(0, 120),
    children: []
  });
}

// ─── Highlight box (shaded paragraph) ────────────────────────
function highlightBox(runs, fill = C.lightBlue) {
  return new Paragraph({
    shading: { fill, type: ShadingType.CLEAR },
    spacing: sp(120, 120),
    indent: { left: 360, right: 360 },
    children: Array.isArray(runs) ? runs : [new TextRun({ text: runs, font: 'Arial', size: 22 })]
  });
}

